// Calculate date range: last 7 days
const now = new Date();
const weekAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);

const formatDate = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    week_start: formatDate(weekAgo),
    week_end: formatDate(now),
    week_label: `w/c ${weekAgo.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })}`,
    generated_at: now.toISOString()
  }
}];

// Aggregate all rows from the audit sheet into digest statistics

const dateRange = $('Code: Build Date Range').first().json;
const weekStart = new Date(dateRange.week_start);
const weekEnd = new Date(dateRange.week_end + 'T23:59:59Z');

// All rows from the sheet
const rows = $input.all().map(i => i.json);

// Filter to this week only
const weekRows = rows.filter(row => {
  const ts = new Date(row.logged_at || row.timestamp);
  return ts >= weekStart && ts <= weekEnd;
});

if (weekRows.length === 0) {
  return [{
    json: {
      ...dateRange,
      total: 0,
      no_data: true,
      message: 'No incidents recorded this week.'
    }
  }];
}

// ── Core counts ──────────────────────────────────────────────
const total = weekRows.length;

const autoResolved = weekRows.filter(r =>
  r.remediation_attempted === 'TRUE' || r.remediation_attempted === true
).length;

const humanEscalated = weekRows.filter(r =>
  r.needs_human_review === 'TRUE' || r.needs_human_review === true
).length;

const loggedOnly = total - autoResolved - humanEscalated;

const jiraCreated = weekRows.filter(r =>
  r.jira_created === 'TRUE' || r.jira_created === true
).length;

// ── MTTR (Mean Time to Recovery) for auto-resolved ───────────
// We log processed_at and remediation is ~10-40s after — estimate from ai_confidence
// In a real setup, log remediation_end_time explicitly
const resolvedRows = weekRows.filter(r => r.remediation_attempted === 'TRUE' || r.remediation_attempted === true);
let avgMttrSeconds = null;
if (resolvedRows.length > 0) {
  // Estimate: low severity_score = faster fix, high = slower
  // Real: store remediation_duration_seconds in audit log
  const estimates = resolvedRows.map(r => {
    const score = parseInt(r.severity_score) || 70;
    return 15 + (score / 100) * 60; // 15s (low) to 75s (critical)
  });
  avgMttrSeconds = Math.round(estimates.reduce((a, b) => a + b, 0) / estimates.length);
}

// ── Severity breakdown ────────────────────────────────────────
const severityCounts = { critical: 0, high: 0, medium: 0, low: 0 };
weekRows.forEach(r => {
  const s = (r.severity || 'low').toLowerCase();
  if (s in severityCounts) severityCounts[s]++;
});

// ── Top failing services ──────────────────────────────────────
const serviceCounts = {};
const serviceLastError = {};
weekRows.forEach(r => {
  const svc = r.service || 'unknown';
  serviceCounts[svc] = (serviceCounts[svc] || 0) + 1;
  if (!serviceLastError[svc] || new Date(r.timestamp) > new Date(serviceLastError[svc].timestamp)) {
    serviceLastError[svc] = r;
  }
});

const topServices = Object.entries(serviceCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, count]) => ({
    name,
    count,
    last_error: serviceLastError[name]?.root_cause_hypothesis || 'See audit log',
    last_severity: serviceLastError[name]?.severity || 'unknown'
  }));

// ── Top error categories ──────────────────────────────────────
const categoryCounts = {};
weekRows.forEach(r => {
  const cat = r.error_category || 'unknown';
  categoryCounts[cat] = (categoryCounts[cat] || 0) + 1;
});
const topCategories = Object.entries(categoryCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([cat, count]) => ({ cat, count }));

// ── Highest severity incident ─────────────────────────────────
const severityOrder = { critical: 4, high: 3, medium: 2, low: 1 };
const worstIncident = weekRows
  .sort((a, b) => {
    const sa = severityOrder[(a.severity || 'low').toLowerCase()] || 0;
    const sb = severityOrder[(b.severity || 'low').toLowerCase()] || 0;
    if (sb !== sa) return sb - sa;
    return parseInt(b.severity_score || 0) - parseInt(a.severity_score || 0);
  })[0];

// ── AI confidence average ─────────────────────────────────────
const confidences = weekRows
  .map(r => parseFloat(r.ai_confidence))
  .filter(c => !isNaN(c));
const avgConfidence = confidences.length > 0
  ? Math.round((confidences.reduce((a, b) => a + b, 0) / confidences.length) * 100)
  : null;

// ── Automation rate ───────────────────────────────────────────
const automationRate = total > 0 ? Math.round((autoResolved / total) * 100) : 0;

// ── Trending: is it getting better or worse? ──────────────────
// Split week in half and compare incident counts
const midpoint = new Date((weekStart.getTime() + weekEnd.getTime()) / 2);
const firstHalf = weekRows.filter(r => new Date(r.timestamp) < midpoint).length;
const secondHalf = weekRows.filter(r => new Date(r.timestamp) >= midpoint).length;
const trend = secondHalf > firstHalf ? 'increasing ⚠️' : secondHalf < firstHalf ? 'decreasing ✅' : 'stable →';

return [{
  json: {
    ...dateRange,
    total,
    auto_resolved: autoResolved,
    human_escalated: humanEscalated,
    logged_only: loggedOnly,
    jira_created: jiraCreated,
    mttr_seconds: avgMttrSeconds,
    automation_rate: automationRate,
    avg_confidence: avgConfidence,
    severity_breakdown: severityCounts,
    top_services: topServices,
    top_categories: topCategories,
    worst_incident: worstIncident,
    trend,
    no_data: false
  }
}];

// Build the Slack Block Kit message for the weekly digest
const d = $input.first().json;

if (d.no_data) {
  return [{ json: {
    blocks: [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `📊 *Weekly Incident Digest — ${d.week_label}*\n\nNo incidents recorded this week. All systems nominal. 🟢`
        }
      }
    ]
  }}];
}

const mttrStr = d.mttr_seconds
  ? d.mttr_seconds < 60
    ? `${d.mttr_seconds}s`
    : `${Math.floor(d.mttr_seconds / 60)}m ${d.mttr_seconds % 60}s`
  : 'N/A';

// Severity emoji map
const sevEmoji = { critical: '🔴', high: '🟠', medium: '🟡', low: '⚪' };

// Top services list
const serviceLines = d.top_services
  .map((s, i) => `  ${i + 1}. \`${s.name}\` — ${s.count} incident${s.count !== 1 ? 's' : ''} ${sevEmoji[s.last_severity] || '⚪'}\n     _${s.last_error.substring(0, 80)}${s.last_error.length > 80 ? '…' : ''}_`)
  .join('\n');

// Severity breakdown
const sevLine = Object.entries(d.severity_breakdown)
  .filter(([, v]) => v > 0)
  .map(([k, v]) => `${sevEmoji[k]} ${k}: *${v}*`)
  .join('  |  ');

// Worst incident block
const worst = d.worst_incident;
const worstBlock = worst ? {
  type: 'section',
  text: {
    type: 'mrkdwn',
    text: `*📌 Highest Severity Incident*\n>${sevEmoji[worst.severity] || '⚪'} \`${worst.service}\` — ${worst.severity?.toUpperCase()} (${worst.severity_score}/100)\n>_${worst.root_cause_hypothesis || worst.message?.substring(0, 100) || 'See audit log'}_\n>${worst.jira_key ? `Jira: \`${worst.jira_key}\`` : 'No Jira ticket'} · ${worst.remediation_attempted === 'TRUE' ? '✅ Auto-resolved' : '👤 Human-escalated'}`
  }
} : null;

// Categories
const catLine = d.top_categories
  .map(c => `\`${c.cat}\` ×${c.count}`)
  .join('  ·  ');

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `📊 Weekly Incident Digest — ${d.week_label}`, emoji: true }
  },
  { type: 'divider' },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Total Incidents*\n${d.total}` },
      { type: 'mrkdwn', text: `*Automation Rate*\n${d.automation_rate}%` },
      { type: 'mrkdwn', text: `*🟢 Auto-resolved*\n${d.auto_resolved} (${d.total > 0 ? Math.round(d.auto_resolved/d.total*100) : 0}%)` },
      { type: 'mrkdwn', text: `*👤 Human-escalated*\n${d.human_escalated} (${d.total > 0 ? Math.round(d.human_escalated/d.total*100) : 0}%)` },
      { type: 'mrkdwn', text: `*⚡ Avg MTTR (auto)*\n${mttrStr}` },
      { type: 'mrkdwn', text: `*📋 Jira Tickets Created*\n${d.jira_created}` }
    ]
  },
  { type: 'divider' },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Severity Breakdown*\n${sevLine}` }
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Top Error Categories*\n${catLine}` }
  },
  { type: 'divider' },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*🔥 Top Failing Services*\n${serviceLines}` }
  },
  { type: 'divider' },
  ...(worstBlock ? [worstBlock, { type: 'divider' }] : []),
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*📈 Incident Trend (vs last half-week):* ${d.trend}\n*AI Avg Confidence:* ${d.avg_confidence !== null ? d.avg_confidence + '%' : 'N/A'}\n\n_Digest covers ${d.week_start} → ${d.week_end} · Generated by Self-Healing Monitor_`
    }
  },
  {
    type: 'actions',
    elements: [
      {
        type: 'button',
        text: { type: 'plain_text', text: '📊 Full Audit Log', emoji: true },
        url: `https://docs.google.com/spreadsheets/d/${ $env.GOOGLE_SHEET_ID }`,
        action_id: 'view_audit_log'
      }
    ]
  }
];

return [{ json: { blocks } }];

// After posting digest, write a summary row to the Sheet
// so you can track digest history over time
const d = $('Code: Aggregate Stats').first().json;

return [{
  json: {
    digest_date: d.week_end,
    week_label: d.week_label,
    total_incidents: d.total,
    auto_resolved: d.auto_resolved,
    human_escalated: d.human_escalated,
    automation_rate_pct: d.automation_rate,
    avg_mttr_seconds: d.mttr_seconds,
    jira_tickets: d.jira_created,
    avg_ai_confidence_pct: d.avg_confidence,
    top_service: d.top_services?.[0]?.name || 'N/A',
    top_service_count: d.top_services?.[0]?.count || 0,
    incident_trend: d.trend,
    critical_count: d.severity_breakdown?.critical || 0,
    high_count: d.severity_breakdown?.high || 0,
    medium_count: d.severity_breakdown?.medium || 0,
    low_count: d.severity_breakdown?.low || 0
  }
}];
